changeSet.sql:
-- Usuń istniejące workouty demo, aby uniknąć duplikatów DELETE FROM workout_set WHERE workout_id IN ( SELECT id FROM workout WHERE user_id = 1 ); DELETE FROM workout WHERE user_id = 1;
-- Kopiuj workouty z kapiet do demo INSERT INTO workout (workout_date, created_by, modified_by, created_on, modified_on, user_id) SELECT workout_date, created_by, modified_by, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 1 FROM workout WHERE user_id = 2;
-- Kopiuj workout_set z kapiet do demo (mapując na nowe workout_id) INSERT INTO workout_set (exercise_id, repetitions, body_part, weight, line_order, workout_id, status) SELECT ws.exercise_id, ws.repetitions, ws.body_part, ws.weight, ws.line_order, w_demo.id, ws.status FROM workout_set ws JOIN workout w_kapiet ON ws.workout_id = w_kapiet.id AND w_kapiet.user_id = 2 JOIN workout w_demo ON w_demo.user_id = 1 AND w_demo.workout_date = w_kapiet.workout_date;
